Designing a memory buffer class that moves resources without re-allocation:

```cpp
#include <utility>

class FMeshBuffer {
private:
    float* VertexData;
    int Size;

public:
    FMeshBuffer(int InSize) : Size(InSize) {
        VertexData = new float[Size];
    }

    ~FMeshBuffer() {
        delete[] VertexData;
    }

    // Move Constructor - Steals resources from temporary object
    FMeshBuffer(FMeshBuffer&& Other) noexcept {
        VertexData = Other.VertexData; // Copy pointer directly
        Size = Other.Size;

        Other.VertexData = nullptr; // Nullify source to prevent deletion
        Other.Size = 0;
    }

    // Move Assignment Operator
    FMeshBuffer& operator=(FMeshBuffer&& Other) noexcept {
        if (this != &Other) {
            delete[] VertexData; // Clean up current resource first

            VertexData = Other.VertexData;
            Size = Other.Size;

            Other.VertexData = nullptr;
            Other.Size = 0;
        }
        return *this;
    }
};
```
